            d = cheb(x, y, rx, ry)
            if d < best:
                best = d
        return best

    best_score = -10**18
    best_move = [0, 0]
    oppd0 = cheb(sx, sy, ox, oy)
    for dx, dy in dirs:
        nx, ny = sx + dx, sy + dy
        if not ok(nx, ny):
            continue
        rd = nearest(nx, ny)
        oppd = cheb(nx, ny, ox, oy)
        score = 0
        if resources:
            score += 100000 - 1000 * rd
        score += (oppd - oppd0) * 50
        if (nx, ny) in resources:
            score += 1000000
        if score > best_score or (score == best_score and (dx, dy) < (best_move[0], best_move[1])):
            best_score = score
            best_move = [dx, dy]

    if ok(sx, sy):
        return best_move if best_move != [0, 0] else [0, 0]
    for dx, dy in dirs:
        if ok(sx + dx, sy + dy):
            return [dx, dy]
    return [0, 0]
